行为模式责任链模式是一种行为设计模式， 允许你将请求沿着处理者链进行发送。 收到请求后， 每个处理者均可对请求进行处理， 或将其传递给链上的下个处理者。 责任链模式Python代码from __future__ import annotations from abc import ABC, abstractmethod from typing import Any, Optional class Handler(ABC): @abstractmethod def set_next(self, handler: Handler) -&gt; Handler: pass @abstractmethod def handle(self, request) -&gt; Optional[str]: pass class AbstractHandler(Handler): _next_handler: Handler = None def set_next(self, handler: Handler) -&gt; Handler: self._next_handler = handler # Returning a handler from here will let us link handlers in a # convenient way like this: # monkey.set_next(squirrel).set_next(dog) return handler @abstractmethod def handle(self, request: Any) -&gt; str: if self._next_handler: return self._next_handler.handle(request) return None class MonkeyHandler(AbstractHandler): def handle(self, request: Any) -&gt; str: if request == &quot;Banana&quot;: return f&quot;Monkey: I&#39;ll eat the {request}&quot; else: return super().handle(request) class SquirrelHandler(AbstractHandler): def handle(self, request: Any) -&gt; str: if request == &quot;Nut&quot;: return f&quot;Squirrel: I&#39;ll eat the {request}&quot; else: return super().handle(request) class DogHandler(AbstractHandler): def handle(self, request: Any) -&gt; str: if request == &quot;MeatBall&quot;: return f&quot;Dog: I&#39;ll eat the {request}&quot; else: return super().handle(request) def client_code(handler: Handler) -&gt; None: for food in [&quot;Nut&quot;, &quot;Banana&quot;, &quot;Cup of coffee&quot;]: print(f&quot;
Client: Who wants a {food}?&quot;) result = handler.handle(food) if result: print(f&quot; {result}&quot;, end=&quot;&quot;) else: print(f&quot; {food} was left untouched.&quot;, end=&quot;&quot;) if __name__ == &quot;__main__&quot;: monkey = MonkeyHandler() squirrel = SquirrelHandler() dog = DogHandler() monkey.set_next(squirrel).set_next(dog) print(&quot;Chain: Monkey &gt; Squirrel &gt; Dog&quot;) client_code(monkey) print(&quot;
&quot;) print(&quot;Subchain: Squirrel &gt; Dog&quot;) client_code(squirrel) # output: # Chain: Monkey &gt; Squirrel &gt; Dog # Client: Who wants a Nut? # Squirrel: I&#39;ll eat the Nut # Client: Who wants a Banana? # Monkey: I&#39;ll eat the Banana # Client: Who wants a Cup of coffee? # Cup of coffee was left untouched. # Subchain: Squirrel &gt; Dog # Client: Who wants a Nut? # Squirrel: I&#39;ll eat the Nut # Client: Who wants a Banana? # Banana was left untouched. # Client: Who wants a Cup of coffee? # Cup of coffee was left untouched. 命令模式命令模式是一种行为设计模式， 它可将请求转换为一个包含与请求相关的所有信息的独立对象。 该转换让你能根据不同的请求将方法参数化、 延迟请求执行或将其放入队列中， 且能实现可撤销操作。 Python代码from __future__ import annotations from abc import ABC, abstractmethod class Command(ABC): @abstractmethod def execute(self) -&gt; None: pass class SimpleCommand(Command): def __init__(self, payload: str) -&gt; None: self._payload = payload def execute(self) -&gt; None: print( f&quot;SimpleCommand: See, I can do simple things like printing&quot;f&quot;({self._payload})&quot;) class ComplexCommand(Command): def __init__(self, receiver: Receiver, a: str, b: str) -&gt; None: self._receiver = receiver self._a = a self._b = b def execute(self) -&gt; None: print(&quot;ComplexCommand: Complex stuff should be done by a receiver object&quot;, end=&quot;&quot;) self._receiver.do_something(self._a) self._receiver.do_something_else(self._b) class Receiver: def do_something(self, a: str) -&gt; None: print(f&quot;
Receiver: Working on ({a}.)&quot;, end=&quot;&quot;) def do_something_else(self, b: str) -&gt; None: print(f&quot;
Receiver: Also working on ({b}.)&quot;, end=&quot;&quot;) class Invoker: _on_start = None _on_finish = None def set_on_start(self, command: Command): self._on_start = command def set_on_finish(self, command: Command): self._on_finish = command def do_something_important(self) -&gt; None: print(&quot;Invoker: Does anybody want something done before I begin?&quot;) if isinstance(self._on_start, Command): self._on_start.execute() print(&quot;Invoker: ...doing something really important...&quot;) print(&quot;Invoker: Does anybody want something done after I finish?&quot;) if isinstance(self._on_finish, Command): self._on_finish.execute() if __name__ == &quot;__main__&quot;: invoker = Invoker() invoker.set_on_start(SimpleCommand(&quot;Say Hi!&quot;)) receiver = Receiver() invoker.set_on_finish(ComplexCommand( receiver, &quot;Send email&quot;, &quot;Save report&quot;)) invoker.do_something_important() # output: # Invoker: Does anybody want something done before I begin? # SimpleCommand: See, I can do simple things like printing(Say Hi!) # Invoker: ...doing something really important... # Invoker: Does anybody want something done after I finish? # ComplexCommand: Complex stuff should be done by a receiver object # Receiver: Working on (Send email.) # Receiver: Also working on (Save report.) 迭代器模式迭代器模式是一种行为设计模式， 让你能在不暴露集合底层表现形式 （列表、 栈和树等） 的情况下遍历集合中所有的元素。 Python代码from __future__ import annotations from collections.abc import Iterable, Iterator from typing import Any, List class AlphabeticalOrderIterator(Iterator): _position: int = None _reverse: bool = False def __init__(self, collection: WordsCollection, reverse: bool = False) -&gt; None: self._collection = collection self._reverse = reverse self._position = -1 if reverse else 0 def __next__(self): try: value = self._collection[self._position] self._position += -1 if self._reverse else 1 except IndexError: raise StopIteration() return value class WordsCollection(Iterable): def __init__(self, collection: List[Any] = []) -&gt; None: self._collection = collection def __iter__(self) -&gt; AlphabeticalOrderIterator: return AlphabeticalOrderIterator(self._collection) def get_reverse_iterator(self) -&gt; AlphabeticalOrderIterator: return AlphabeticalOrderIterator(self._collection, True) def add_item(self, item: Any): self._collection.append(item) if __name__ == &quot;__main__&quot;: collection = WordsCollection() collection.add_item(&quot;First&quot;) collection.add_item(&quot;Second&quot;) collection.add_item(&quot;Third&quot;) print(&quot;Straight traversal:&quot;) print(&quot;
&quot;.join(collection)) print(&quot;&quot;) print(&quot;Reverse traversal:&quot;) print(&quot;
&quot;.join(collection.get_reverse_iterator()), end=&quot;&quot;) # output: # Straight traversal: # First # Second # Third # Reverse traversal: # Third # Second # First 中介者模式中介者模式是一种行为设计模式， 能让你减少对象之间混乱无序的依赖关系。 该模式会限制对象之间的直接交互， 迫使它们通过一个中介者对象进行合作。 Python代码from __future__ import annotations from abc import ABC class Mediator(ABC): def notify(self, sender: object, event: str) -&gt; None: pass class ConcreteMediator(Mediator): def __init__(self, component1: Component1, component2: Component2) -&gt; None: self._component1 = component1 self._component1.mediator = self self._component2 = component2 self._component2.mediator = self def notify(self, sender: object, event: str) -&gt; None: if event == &quot;A&quot;: print(&quot;Mediator reacts on A and triggers following operations:&quot;) self._component2.do_c() elif event == &quot;D&quot;: print(&quot;Mediator reacts on D and triggers following operations:&quot;) self._component1.do_b() self._component2.do_c() class BaseComponent: def __init__(self, mediator: Mediator = None) -&gt; None: self._mediator = mediator @property def mediator(self) -&gt; Mediator: return self._mediator @mediator.setter def mediator(self, mediator: Mediator) -&gt; None: self._mediator = mediator class Component1(BaseComponent): def do_a(self) -&gt; None: print(&quot;Component 1 does A.&quot;) self.mediator.notify(self, &quot;A&quot;) def do_b(self) -&gt; None: print(&quot;Component 1 does B.&quot;) self.mediator.notify(self, &quot;B&quot;) class Component2(BaseComponent): def do_c(self) -&gt; None: print(&quot;Component 2 does C.&quot;) self.mediator.notify(self, &quot;C&quot;) def do_d(self) -&gt; None: print(&quot;Component 2 does D.&quot;) self.mediator.notify(self, &quot;D&quot;) if __name__ == &quot;__main__&quot;: c1 = Component1() c2 = Component2() mediator = ConcreteMediator(c1, c2) print(&quot;Client triggers operation A.&quot;) c1.do_a() print(&quot;
&quot;, end=&quot;&quot;) print(&quot;Client triggers operation D.&quot;) c2.do_d() # output: # Client triggers operation A. # Component 1 does A. # Mediator reacts on A and triggers following operations: # Component 2 does C. # Client triggers operation D. # Component 2 does D. # Mediator reacts on D and triggers following operations: # Component 1 does B. # Component 2 does C. 备忘录模式备忘录模式是一种行为设计模式， 允许在不暴露对象实现细节的情况下保存和恢复对象之前的状态。 Python代码from __future__ import annotations from abc import ABC, abstractmethod from datetime import datetime from random import sample from string import ascii_letters, digits class Originator(): _state = None def __init__(self, state: str) -&gt; None: self._state = state print(f&quot;Originator: My initial state is: {self._state}&quot;) def do_something(self) -&gt; None: print(&quot;Originator: I&#39;m doing something important.&quot;) self._state = self._generate_random_string(30) print(f&quot;Originator: and my state has changed to: {self._state}&quot;) def _generate_random_string(self, length: int = 10) -&gt; None: return &quot;&quot;.join(sample(ascii_letters, length)) def save(self) -&gt; Memento: return ConcreteMemento(self._state) def restore(self, memento: Memento) -&gt; None: &quot;&quot;&quot; Restores the Originator&#39;s state from a memento object. &quot;&quot;&quot; self._state = memento.get_state() print(f&quot;Originator: My state has changed to: {self._state}&quot;) class Memento(ABC): @abstractmethod def get_name(self) -&gt; str: pass @abstractmethod def get_date(self) -&gt; str: pass class ConcreteMemento(Memento): def __init__(self, state: str) -&gt; None: self._state = state self._date = str(datetime.now())[:19] def get_state(self) -&gt; str: &quot;&quot;&quot; The Originator uses this method when restoring its state. &quot;&quot;&quot; return self._state def get_name(self) -&gt; str: &quot;&quot;&quot; The rest of the methods are used by the Caretaker to display metadata. &quot;&quot;&quot; return f&quot;{self._date} / ({self._state[0:9]}...)&quot; def get_date(self) -&gt; str: return self._date class Caretaker(): def __init__(self, originator: Originator) -&gt; None: self._mementos = [] self._originator = originator def backup(self) -&gt; None: print(&quot;
Caretaker: Saving Originator&#39;s state...&quot;) self._mementos.append(self._originator.save()) def undo(self) -&gt; None: if not len(self._mementos): return memento = self._mementos.pop() print(f&quot;Caretaker: Restoring state to: {memento.get_name()}&quot;) try: self._originator.restore(memento) except Exception: self.undo() def show_history(self) -&gt; None: print(&quot;Caretaker: Here&#39;s the list of mementos:&quot;) for memento in self._mementos: print(memento.get_name()) if __name__ == &quot;__main__&quot;: originator = Originator(&quot;Super-duper-super-puper-super.&quot;) caretaker = Caretaker(originator) caretaker.backup() originator.do_something() caretaker.backup() originator.do_something() caretaker.backup() originator.do_something() print() caretaker.show_history() print(&quot;
Client: Now, let&#39;s rollback!
&quot;) caretaker.undo() print(&quot;
Client: Once more!
&quot;) caretaker.undo() # output: # Originator: My initial state is: Super-duper-super-puper-super. # Caretaker: Saving Originator&#39;s state... # Originator: I&#39;m doing something important. # Originator: and my state has changed to: mEOzwWHfnTMZYsplgQrtIxjqeVJNRX # Caretaker: Saving Originator&#39;s state... # Originator: I&#39;m doing something important. # Originator: and my state has changed to: VXFgbuBNUZIRDrwThxSiPJcHlevAGo # Caretaker: Saving Originator&#39;s state... # Originator: I&#39;m doing something important. # Originator: and my state has changed to: ifIzXcxHLrltsdqyWRpMTNYoZvBCVb # Caretaker: Here&#39;s the list of mementos: # 2020-12-02 17:05:55 / (Super-dup...) # 2020-12-02 17:05:55 / (mEOzwWHfn...) # 2020-12-02 17:05:55 / (VXFgbuBNU...) # Client: Now, let&#39;s rollback! # Caretaker: Restoring state to: 2020-12-02 17:05:55 / (VXFgbuBNU...) # Originator: My state has changed to: VXFgbuBNUZIRDrwThxSiPJcHlevAGo # Client: Once more! # Caretaker: Restoring state to: 2020-12-02 17:05:55 / (mEOzwWHfn...) # Originator: My state has changed to: mEOzwWHfnTMZYsplgQrtIxjqeVJNRX 观察者模式观察者模式是一种行为设计模式， 允许你定义一种订阅机制， 可在对象事件发生时通知多个 “观察” 该对象的其他对象。 Python代码from __future__ import annotations from abc import ABC, abstractmethod from random import randrange from typing import List class Subject(ABC): @abstractmethod def attach(self, observer: Observer) -&gt; None: pass @abstractmethod def detach(self, observer: Observer) -&gt; None: pass @abstractmethod def notify(self) -&gt; None: pass class ConcreteSubject(Subject): _state: int = None _observers: List[Observer] = [] def attach(self, observer: Observer) -&gt; None: print(&quot;Subject: Attached an observer.&quot;) self._observers.append(observer) def detach(self, observer: Observer) -&gt; None: self._observers.remove(observer) def notify(self) -&gt; None: print(&quot;Subject: Notifying observers...&quot;) for observer in self._observers: observer.update(self) def some_business_logic(self) -&gt; None: print(&quot;
Subject: I&#39;m doing something important.&quot;) self._state = randrange(0, 10) print(f&quot;Subject: My state has just changed to: {self._state}&quot;) self.notify() class Observer(ABC): @abstractmethod def update(self, subject: Subject) -&gt; None: &quot;&quot;&quot; Receive update from subject. &quot;&quot;&quot; pass class ConcreteObserverA(Observer): def update(self, subject: Subject) -&gt; None: if subject._state &lt; 3: print(&quot;ConcreteObserverA: Reacted to the event&quot;) class ConcreteObserverB(Observer): def update(self, subject: Subject) -&gt; None: if subject._state == 0 or subject._state &gt;= 2: print(&quot;ConcreteObserverB: Reacted to the event&quot;) if __name__ == &quot;__main__&quot;: subject = ConcreteSubject() observer_a = ConcreteObserverA() subject.attach(observer_a) observer_b = ConcreteObserverB() subject.attach(observer_b) subject.some_business_logic() subject.some_business_logic() subject.detach(observer_a) subject.some_business_logic() # output: # Subject: Attached an observer. # Subject: Attached an observer. # Subject: I&#39;m doing something important. # Subject: My state has just changed to: 2 # Subject: Notifying observers... # ConcreteObserverA: Reacted to the event # ConcreteObserverB: Reacted to the event # Subject: I&#39;m doing something important. # Subject: My state has just changed to: 0 # Subject: Notifying observers... # ConcreteObserverA: Reacted to the event # ConcreteObserverB: Reacted to the event # Subject: I&#39;m doing something important. # Subject: My state has just changed to: 9 # Subject: Notifying observers... # ConcreteObserverB: Reacted to the event 状态模式状态模式是一种行为设计模式， 让你能在一个对象的内部状态变化时改变其行为， 使其看上去就像改变了自身所属的类一样。 Python代码from __future__ import annotations from abc import ABC, abstractmethod class Context: _state = None def __init__(self, state: State) -&gt; None: self.transition_to(state) def transition_to(self, state: State): print(f&quot;Context: Transition to {type(state).__name__}&quot;) self._state = state self._state.context = self def request1(self): self._state.handle1() def request2(self): self._state.handle2() class State(ABC): @property def context(self) -&gt; Context: return self._context @context.setter def context(self, context: Context) -&gt; None: self._context = context @abstractmethod def handle1(self) -&gt; None: pass @abstractmethod def handle2(self) -&gt; None: pass class ConcreteStateA(State): def handle1(self) -&gt; None: print(&quot;ConcreteStateA handles request1.&quot;) print(&quot;ConcreteStateA wants to change the state of the context.&quot;) self.context.transition_to(ConcreteStateB()) def handle2(self) -&gt; None: print(&quot;ConcreteStateA handles request2.&quot;) class ConcreteStateB(State): def handle1(self) -&gt; None: print(&quot;ConcreteStateB handles request1.&quot;) def handle2(self) -&gt; None: print(&quot;ConcreteStateB handles request2.&quot;) print(&quot;ConcreteStateB wants to change the state of the context.&quot;) self.context.transition_to(ConcreteStateA()) if __name__ == &quot;__main__&quot;: context = Context(ConcreteStateA()) context.request1() context.request2() # output: # Context: Transition to ConcreteStateA # ConcreteStateA handles request1. # ConcreteStateA wants to change the state of the context. # Context: Transition to ConcreteStateB # ConcreteStateB handles request2. # ConcreteStateB wants to change the state of the context. # Context: Transition to ConcreteStateA 策略模式策略模式是一种行为设计模式， 它能让你定义一系列算法， 并将每种算法分别放入独立的类中， 以使算法的对象能够相互替换。 Python代码from __future__ import annotations from abc import ABC, abstractmethod from typing import List class Context(): def __init__(self, strategy: Strategy) -&gt; None: self._strategy = strategy @property def strategy(self) -&gt; Strategy: return self._strategy @strategy.setter def strategy(self, strategy: Strategy) -&gt; None: self._strategy = strategy def do_some_business_logic(self) -&gt; None: print(&quot;Context: Sorting data using the strategy (not sure how it&#39;ll do it)&quot;) result = self._strategy.do_algorithm([&quot;a&quot;, &quot;b&quot;, &quot;c&quot;, &quot;d&quot;, &quot;e&quot;]) print(&quot;,&quot;.join(result)) class Strategy(ABC): @abstractmethod def do_algorithm(self, data: List): pass class ConcreteStrategyA(Strategy): def do_algorithm(self, data: List) -&gt; List: return sorted(data) class ConcreteStrategyB(Strategy): def do_algorithm(self, data: List) -&gt; List: return reversed(sorted(data)) if __name__ == &quot;__main__&quot;: context = Context(ConcreteStrategyA()) print(&quot;Client: Strategy is set to normal sorting.&quot;) context.do_some_business_logic() print() print(&quot;Client: Strategy is set to reverse sorting.&quot;) context.strategy = ConcreteStrategyB() context.do_some_business_logic() output: Client: Strategy is set to normal sorting. Context: Sorting data using the strategy (not sure how it&#39;ll do it) a,b,c,d,e Client: Strategy is set to reverse sorting. Context: Sorting data using the strategy (not sure how it&#39;ll do it) e,d,c,b,a 模板方法模式模板方法模式是一种行为设计模式， 它在超类中定义了一个算法的框架， 允许子类在不修改结构的情况下重写算法的特定步骤。 Python代码from abc import ABC, abstractmethod class AbstractClass(ABC): def template_method(self) -&gt; None: self.base_operation1() self.required_operations1() self.base_operation2() self.hook1() self.required_operations2() self.base_operation3() self.hook2() def base_operation1(self) -&gt; None: print(&quot;AbstractClass says: I am doing the bulk of the work&quot;) def base_operation2(self) -&gt; None: print(&quot;AbstractClass says: But I let subclasses override some operations&quot;) def base_operation3(self) -&gt; None: print(&quot;AbstractClass says: But I am doing the bulk of the work anyway&quot;) @abstractmethod def required_operations1(self) -&gt; None: pass @abstractmethod def required_operations2(self) -&gt; None: pass def hook1(self) -&gt; None: pass def hook2(self) -&gt; None: pass class ConcreteClass1(AbstractClass): def required_operations1(self) -&gt; None: print(&quot;ConcreteClass1 says: Implemented Operation1&quot;) def required_operations2(self) -&gt; None: print(&quot;ConcreteClass1 says: Implemented Operation2&quot;) class ConcreteClass2(AbstractClass): def required_operations1(self) -&gt; None: print(&quot;ConcreteClass2 says: Implemented Operation1&quot;) def required_operations2(self) -&gt; None: print(&quot;ConcreteClass2 says: Implemented Operation2&quot;) def hook1(self) -&gt; None: print(&quot;ConcreteClass2 says: Overridden Hook1&quot;) def client_code(abstract_class: AbstractClass) -&gt; None: abstract_class.template_method() if __name__ == &quot;__main__&quot;: print(&quot;Same client code can work with different subclasses:&quot;) client_code(ConcreteClass1()) print(&quot;&quot;) print(&quot;Same client code can work with different subclasses:&quot;) client_code(ConcreteClass2()) # output: # Same client code can work with different subclasses: # AbstractClass says: I am doing the bulk of the work # ConcreteClass1 says: Implemented Operation1 # AbstractClass says: But I let subclasses override some operations # ConcreteClass1 says: Implemented Operation2 # AbstractClass says: But I am doing the bulk of the work anyway # Same client code can work with different subclasses: # AbstractClass says: I am doing the bulk of the work # ConcreteClass2 says: Implemented Operation1 # AbstractClass says: But I let subclasses override some operations # ConcreteClass2 says: Overridden Hook1 # ConcreteClass2 says: Implemented Operation2 # AbstractClass says: But I am doing the bulk of the work anyway 访问者模式访问者模式是一种行为设计模式， 它能将算法与其所作用的对象隔离开来。 Python代码from __future__ import annotations from abc import ABC, abstractmethod from typing import List class Component(ABC): @abstractmethod def accept(self, visitor: Visitor) -&gt; None: pass class ConcreteComponentA(Component): def accept(self, visitor: Visitor) -&gt; None: visitor.visit_concrete_component_a(self) def exclusive_method_of_concrete_component_a(self) -&gt; str: return &quot;A&quot; class ConcreteComponentB(Component): def accept(self, visitor: Visitor): visitor.visit_concrete_component_b(self) def special_method_of_concrete_component_b(self) -&gt; str: return &quot;B&quot; class Visitor(ABC): @abstractmethod def visit_concrete_component_a(self, element: ConcreteComponentA) -&gt; None: pass @abstractmethod def visit_concrete_component_b(self, element: ConcreteComponentB) -&gt; None: pass class ConcreteVisitor1(Visitor): def visit_concrete_component_a(self, element) -&gt; None: print( f&quot;{element.exclusive_method_of_concrete_component_a()} + ConcreteVisitor1&quot;) def visit_concrete_component_b(self, element) -&gt; None: print(f&quot;{element.special_method_of_concrete_component_b()} + ConcreteVisitor1&quot;) class ConcreteVisitor2(Visitor): def visit_concrete_component_a(self, element) -&gt; None: print( f&quot;{element.exclusive_method_of_concrete_component_a()} + ConcreteVisitor2&quot;) def visit_concrete_component_b(self, element) -&gt; None: print(f&quot;{element.special_method_of_concrete_component_b()} + ConcreteVisitor2&quot;) def client_code(components: List[Component], visitor: Visitor) -&gt; None: for component in components: component.accept(visitor) if __name__ == &quot;__main__&quot;: components = [ConcreteComponentA(), ConcreteComponentB()] print(&quot;The client code works with all visitors via the base Visitor interface:&quot;) visitor1 = ConcreteVisitor1() client_code(components, visitor1) print(&quot;It allows the same client code to work with different types of visitors:&quot;) visitor2 = ConcreteVisitor2() client_code(components, visitor2) # output: # The client code works with all visitors via the base Visitor interface: # A + ConcreteVisitor1 # B + ConcreteVisitor1 # It allows the same client code to work with different types of visitors: # A + ConcreteVisitor2 # B + ConcreteVisitor2

