ration()}&quot;, end=&quot;&quot;) def client_code2(component1: Component, component2: Component) -&gt; None: if component1.is_composite(): component1.add(component2) print(f&quot;RESULT: {component1.operation()}&quot;, end=&quot;&quot;) if __name__ == &quot;__main__&quot;: simple = Leaf() print(&quot;Client: I&#39;ve got a simple component:&quot;) client_code(simple) print(&#39;
