tate: Dict) -&gt; Flyweight: key = self.get_key(shared_state) if not self._flyweights.get(key): print(&quot;FlyweightFactory: Can&#39;t find a flyweight, creating new one.&quot;) self._flyweights[key] = Flyweight(shared_state) else: print(&quot;FlyweightFactory: Reusing existing flyweight.&quot;) return self._flyweights[key] def list_flyweights(self) -&gt; None: count = len(self._flyweights) print(f&quot;FlyweightFactory: I have {count} flyweights:&quot;) print(&quot;
