Client: Adding a car to database.&quot;) flyweight = factory.get_flyweight([brand, model, color]) flyweight.operation([plates, owner]) if __name__ == &quot;__main__&quot;: factory = FlyweightFactory([ [&quot;Chevrolet&quot;, &quot;Camaro2018&quot;, &quot;pink&quot;], [&quot;Mercedes Benz&quot;, &quot;C300&quot;, &quot;black&quot;], [&quot;Mercedes Benz&quot;, &quot;C500&quot;, &quot;red&quot;], [&quot;BMW&quot;, &quot;M5&quot;, &quot;red&quot;], [&quot;BMW&quot;, &quot;X6&quot;, &quot;white&quot;], ]) factory.list_flyweights() add_car_to_police_database( factory, &quot;CL234IR&quot;, &quot;James Doe&quot;, &quot;BMW&quot;, &quot;M5&quot;, &quot;red&quot;) add_car_to_police_database( factory, &quot;CL234IR&quot;, &quot;James Doe&quot;, &quot;BMW&quot;, &quot;X1&quot;, &quot;red&quot;) print(&quot;
