eteProductB1(AbstractProductB): def another_useful_function_b(self, collaborator: AbstractProductA) -&gt; str: result = collaborator.useful_function_a() return f&quot;The result of the B1 collaborating with the ({result})&quot; def useful_function_b(self) -&gt; str: return &quot;The result of the product B1.&quot; # 抽象产品B2 class ConcreteProductB2(AbstractProductB): def useful_function_b(self) -&gt; str: return &quot;The result of the product B2.&quot; def another_useful_function_b(self, collaborator: AbstractProductA) -&gt; str: result = collaborator.useful_function_a() return f&quot;The result of the B2 collaborating with the ({result})&quot; def client_code(factory: AbstractFactory) -&gt; None: product_a = factory.create_product_a() product_b = factory.create_product_b() print(f&quot;{product_b.useful_function_b()}&quot;) print(f&quot;{product_b.another_useful_function_b(product_a)}&quot;, end=&quot;&quot;) if __name__ == &quot;__main__&quot;: print(&quot;Client: Testing client code with the first factory type:&quot;) client_code(ConcreteFactory1()) print(&quot;
